## Step 2: Create `test/github-install.e2e-spec.ts`

```typescript
import { HttpStatus } from '@nestjs/common';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import { Test, TestingModule } from '@nestjs/testing';
import * as request from 'supertest';

import { EnvConfigService } from '@modules/env-config/env-config.service';
import { GithubInstallController } from '@modules/github/github-install.controller';
import { GithubInstallService } from '@modules/github/github-install.service';
import {
  GithubInstallationStatus,
  IGithubInstallationBase,
} from '@modules/github/types/github-installation.interface';

const mockInstallation: IGithubInstallationBase = {
  _id: 'install-uuid-1',
  company_id: 'company-uuid-1',
  installation_id: 12345678,
  org_login: 'acme-corp',
  org_id: 987654,
  status: GithubInstallationStatus.ACTIVE,
  installed_at: new Date('2026-04-14'),
  suspended_at: null,
  uninstalled_at: null,
  created_at: new Date('2026-04-14'),
  updated_at: new Date('2026-04-14'),
};

const mockInstallService = {
  initiateConnect: jest.fn(),
  handleCallback: jest.fn(),
  disconnect: jest.fn(),
};

const mockConfigService = {
  get: jest.fn().mockReturnValue('http://localhost:3000'),
};

describe('GithubInstallController (e2e)', () => {
  let app: NestFastifyApplication;

  beforeAll(async () => {
    const moduleFixture: TestingModule = await Test.createTestingModule({
      controllers: [GithubInstallController],
      providers: [
        { provide: GithubInstallService, useValue: mockInstallService },
        { provide: EnvConfigService, useValue: mockConfigService },
      ],
    }).compile();

    app = moduleFixture.createNestApplication<NestFastifyApplication>(new FastifyAdapter());
    await app.init();
    await app.getHttpAdapter().getInstance().ready();
  });

  afterAll(async () => {
    await app.close();
  });

  beforeEach(() => jest.clearAllMocks());

  describe('POST /integrations/github/connect', () => {
    it('should return 200 with redirect URL', async () => {
      const url = 'https://github.com/apps/my-app/installations/new?state=abc123';
      mockInstallService.initiateConnect.mockResolvedValue(url);

      const res = await request(app.getHttpServer())
        .post('/integrations/github/connect')
        .send();

      expect(res.status).toBe(HttpStatus.OK);
      expect(res.body).toEqual({ url });
    });
  });

  describe('GET /integrations/github/callback', () => {
    it('should redirect to frontend on success', async () => {
      mockInstallService.handleCallback.mockResolvedValue(mockInstallation);

      const res = await request(app.getHttpServer())
        .get('/integrations/github/callback')
        .query({ installation_id: '12345678', state: 'abc123', setup_action: 'install' });

      expect(res.status).toBe(HttpStatus.FOUND);
      expect(res.headers['location']).toContain('/settings/integrations');
    });

    it('should redirect to error page when callback fails', async () => {
      mockInstallService.handleCallback.mockRejectedValue(new Error('Invalid state'));

      const res = await request(app.getHttpServer())
        .get('/integrations/github/callback')
        .query({ installation_id: '12345678', state: 'bad', setup_action: 'install' });

      expect(res.status).toBe(HttpStatus.FOUND);
      expect(res.headers['location']).toContain('/settings/integrations?error=');
    });
  });

  describe('DELETE /integrations/github/installations/:id', () => {
    it('should return 204 on success', async () => {
      mockInstallService.disconnect.mockResolvedValue(undefined);

      const res = await request(app.getHttpServer())
        .delete('/integrations/github/installations/install-uuid-1')
        .send();

      expect(res.status).toBe(HttpStatus.NO_CONTENT);
    });
  });
});
```

## Step 3: Create `test/github-webhook.e2e-spec.ts`

```typescript
import { HttpStatus } from '@nestjs/common';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import { Test, TestingModule } from '@nestjs/testing';
import * as request from 'supertest';

import { GithubWebhookController } from '@modules/github/github-webhook.controller';
import { GithubWebhookService } from '@modules/github/github-webhook.service';

const mockWebhookService = {
  verifySignature: jest.fn(),
  handleEvent: jest.fn(),
};

describe('GithubWebhookController (e2e)', () => {
  let app: NestFastifyApplication;

  beforeAll(async () => {
    const moduleFixture: TestingModule = await Test.createTestingModule({
      controllers: [GithubWebhookController],
      providers: [{ provide: GithubWebhookService, useValue: mockWebhookService }],
    }).compile();

    app = moduleFixture.createNestApplication<NestFastifyApplication>(new FastifyAdapter());
    await app.init();
    await app.getHttpAdapter().getInstance().ready();
  });

  afterAll(async () => {
    await app.close();
  });

  beforeEach(() => jest.clearAllMocks());

  describe('POST /integrations/github/webhook', () => {
    it('should return 401 when signature is invalid', async () => {
      mockWebhookService.verifySignature.mockReturnValue(false);

      const res = await request(app.getHttpServer())
        .post('/integrations/github/webhook')
        .set('x-github-event', 'push')
        .set('x-hub-signature-256', 'sha256=invalid')
        .set('x-github-hook-installation-target-id', '12345678')
        .send('{"ref":"refs/heads/main"}');

      expect(res.status).toBe(HttpStatus.UNAUTHORIZED);
    });

    it('should return 200 when signature is valid', async () => {
      mockWebhookService.verifySignature.mockReturnValue(true);
      mockWebhookService.handleEvent.mockResolvedValue(undefined);

      const res = await request(app.getHttpServer())
        .post('/integrations/github/webhook')
        .set('x-github-event', 'push')
        .set('x-hub-signature-256', 'sha256=valid')
        .set('x-github-hook-installation-target-id', '12345678')
        .send('{"ref":"refs/heads/main"}');

      expect(res.status).toBe(HttpStatus.OK);
      expect(mockWebhookService.handleEvent).toHaveBeenCalled();
    });
  });
});
```

