26	@ApiTags('GitHub Integration')
27	@Controller('integrations/github')
28	export class GithubInstallController {
29		constructor(
30			private readonly githubInstallService: GithubInstallService,
31			private readonly configService: EnvConfigService,
32		) {}
33	
34		@Post('connect')
35		@Roles('admin')
36		@HttpCode(HttpStatus.OK)
37		@ApiOperation({ summary: 'Initiate GitHub App installation' })
38		@ApiResponse({ status: HttpStatus.OK, description: 'Returns GitHub install URL' })
39		@LogExecution()
40		async connect(@CurrentUser() user: IRequestUser): Promise<{ url: string }> {
41			// eslint-disable-next-line @typescript-eslint/no-non-null-assertion
42			const companyId = user.company_id!;
43			const url = await this.githubInstallService.initiateConnect({
44				companyId,
45				userId: user.user_id,
46			});
47			return { url };
48		}
49	
50		@Get('callback')
51		@Roles('admin')
52		@ApiOperation({ summary: 'GitHub App installation callback' })
53		@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirects to frontend' })
54		@LogExecution()
55		async callback(
56			@Query() query: { installation_id: string; state: string; setup_action: string },
57			@Res() reply: FastifyReply,
58		): Promise<void> {
59			const frontendUrl = this.configService.get<string>({ key: FRONTEND_URL });
60	
61			try {
62				await this.githubInstallService.handleCallback({
63					installationId: Number(query.installation_id),
64					state: query.state,
65				});
66	
67				await reply.redirect(`${frontendUrl}/settings/integrations?connected=github`);
68			} catch {
69				await reply.redirect(
70					`${frontendUrl}/settings/integrations?error=github_connect_failed`,
71				);
72			}
73		}
74	
75		@Delete('installations/:id')
76		@Roles('admin')
77		@HttpCode(HttpStatus.NO_CONTENT)
78		@ApiOperation({ summary: 'Disconnect GitHub installation' })
79		@ApiResponse({
80			status: HttpStatus.NO_CONTENT,
81			description: 'Installation disconnected',
82		})
83		@LogExecution()
84		async disconnect(
