1	import {
2		Body,
3		Controller,
4		Headers,
5		HttpCode,
6		HttpStatus,
7		Post,
8		UnauthorizedException,
9	} from '@nestjs/common';
10	import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
11	
12	import { Public } from '@modules/auth/decorators/public.decorator';
13	import { GithubWebhookService } from '@modules/github/github-webhook.service';
14	
15	import { LogExecution } from '@decorators/log-execution.decorator';
16	
17	@ApiTags('GitHub Webhooks')
18	@Controller('integrations/github')
19	export class GithubWebhookController {
20		constructor(private readonly githubWebhookService: GithubWebhookService) {}
21	
22		@Post('webhook')
23		@Public()
24		@HttpCode(HttpStatus.OK)
25		@ApiOperation({ summary: 'Receive GitHub App webhook events' })
26		@ApiResponse({ status: HttpStatus.OK, description: 'Event received' })
27		@ApiResponse({ status: HttpStatus.UNAUTHORIZED, description: 'Invalid signature' })
28		@LogExecution()
29		async handleWebhook(
30			@Headers() headers: Record<string, string>,
31			@Body() rawBody: string,
32		): Promise<void> {
33			const signature = headers['x-hub-signature-256'] ?? '';
34			const event = headers['x-github-event'] ?? '';
35			const installationIdRaw = headers['x-github-hook-installation-target-id'] ?? '0';
36	
37			const isValid = this.githubWebhookService.verifySignature({
38				payload: rawBody,
39				signature,
40			});
41	
42			if (!isValid) {
43				throw new UnauthorizedException('Invalid webhook signature');
44			}
45	
46			const payload = JSON.parse(rawBody) as unknown;
47	
48			await this.githubWebhookService.handleEvent({
49				event,
50				installationId: Number(installationIdRaw),
51				payload,
52			});
53		}
54	}
