3	import { Logger } from '@nestjs/common';
4	
5	const EXECUTION_TIME_THRESHOLD_MS = 3000;
6	
7	export interface LogExecutionOptions<TParams = unknown, TResponse = unknown> {
8		logParams?: boolean;
9		logResponse?: boolean;
10		logExecutionTime?: boolean;
11		maskSensitiveData?: boolean;
12		sensitiveKeys?: string[];
13		customContext?: Record<string, unknown>;
14		paramFormatter?: (params: TParams) => unknown;
15		responseFormatter?: (response: TResponse) => unknown;
16	}
17	
18	const DEFAULT_SENSITIVE_KEYS: string[] = [
19		'password',
20		'pass',
21		'token',
22		'secret',
23		'auth',
24		'authorization',
25		'cookie',
26		'session',
27		'credentials',
28		'apiKey',
29		'csrf',
30		'refreshToken',
31		'accessToken',
32	];
33	
34	const DEFAULT_OPTIONS: LogExecutionOptions = {
35		logParams: true,
36		logResponse: true,
37		logExecutionTime: true,
38		maskSensitiveData: true,
39		sensitiveKeys: DEFAULT_SENSITIVE_KEYS,
40	};
41	
42	const REQUEST_LIKE_KEYS = new Set([
43		'raw',
44		'socket',
45		'headers',
46		'hostname',
47		'ip',
48		'protocol',
49		'routeOptions',
50		'routerPath',
51	]);
52	
53	function isRequestObject(value: unknown): boolean {
54		if (!value || typeof value !== 'object') return false;
55		const keys = Object.keys(value as Record<string, unknown>);
56		return REQUEST_LIKE_KEYS.has(keys[0] ?? '') && keys.length > 5;
57	}
58	
59	function isResponseObject(value: unknown): boolean {
60		if (!value || typeof value !== 'object') return false;
61		const obj = value as Record<string, unknown>;
62		return typeof obj['send'] === 'function' && typeof obj['status'] === 'function';
63	}
64	
65	function extractRequestInfo(req: Record<string, unknown>): Record<string, unknown> {
66		return {
67			method: req['method'],
68			url: req['url'],
69			ip: req['ip'],
70			userAgent: (req['headers'] as Record<string, unknown> | undefined)?.['user-agent'],
71		};
72	}
73	
74	function sanitizeArgs(args: unknown[]): unknown[] {
75		return args.map((arg) => {
76			if (isRequestObject(arg)) return extractRequestInfo(arg as Record<string, unknown>);
77			if (isResponseObject(arg)) return '[FastifyReply]';
78			return arg;
79		});
80	}
81	
82	export function maskSensitiveData(
83		data: unknown,
84		sensitiveKeys: string[] = DEFAULT_SENSITIVE_KEYS,
85	): unknown {
86		if (!data || typeof data !== 'object') return data;
87	
88		if (Array.isArray(data)) {
89			return data.map((item) => maskSensitiveData(item, sensitiveKeys));
90		}
91	
92		const masked = { ...data } as Record<string, unknown>;
93	
94		for (const key in masked) {
95			if (!Object.prototype.hasOwnProperty.call(masked, key)) continue;
96	
97			const lowerKey = key.toLowerCase();
98	
99			if (sensitiveKeys.some((sk) => lowerKey.includes(sk.toLowerCase()))) {
100				masked[key] = '***MASKED***';
101			} else if (typeof masked[key] === 'object' && masked[key] !== null) {
102				masked[key] = maskSensitiveData(masked[key], sensitiveKeys);
103			}
104		}
105	
106		return masked;
107	}
108	
109	export function LogExecution<TParams = unknown, TResponse = unknown>(
110		options: LogExecutionOptions<TParams, TResponse> = {},
111	): MethodDecorator {
112		const config = { ...DEFAULT_OPTIONS, ...options };
113	
114		return function (
115			target: unknown,
116			propertyKey: string | symbol,
117			descriptor: PropertyDescriptor,
118		): PropertyDescriptor {
119			const originalMethod = descriptor.value as (...args: unknown[]) => unknown;
120			const className = (target as { constructor: { name: string } }).constructor.name;
121			const methodName = String(propertyKey);
122			const logger = new Logger(`${className}.${methodName}`);
123	
124			descriptor.value = async function (...args: unknown[]) {
125				const startTime = performance.now();
126	
127				try {
128					const logContext = {
129						className,
130						methodName,
131						timestamp: new Date().toISOString(),
132						...(config.customContext ?? {}),
133					};
134	
135					if (config.logParams) {
136						let paramsToLog: unknown = config.paramFormatter
137							? config.paramFormatter(args as TParams)
138							: sanitizeArgs(args);
139	
140						if (config.maskSensitiveData) {
141							paramsToLog = maskSensitiveData(paramsToLog, config.sensitiveKeys);
142						}
143	
144						logger.log(
145							`Invoked | ${JSON.stringify({ params: paramsToLog, ...logContext })}`,
146						);
147					}
148	
149					const result = await originalMethod.apply(this, args);
150					const executionTime = performance.now() - startTime;
151	
152					if (config.logExecutionTime) {
153						let responseToLog: unknown = config.responseFormatter
154							? config.responseFormatter(result as TResponse)
155							: result;
156	
157						if (config.maskSensitiveData) {
158							responseToLog = maskSensitiveData(responseToLog, config.sensitiveKeys);
159						}
160	
161						const successContext = {
162							...logContext,
163							executionTimeMs: Math.round(executionTime * 100) / 100,
164							...(config.logResponse ? { response: responseToLog } : {}),
165						};
166	
167						logger.log(
168							`Completed in ${executionTime.toFixed(2)}ms | ${JSON.stringify(successContext)}`,
169						);
170					}
171	
172					if (executionTime > EXECUTION_TIME_THRESHOLD_MS) {
173						logger.warn(
174							`Slow execution: ${executionTime.toFixed(2)}ms | ${className}.${methodName}`,
175						);
176					}
177	
178					return result;
179				} catch (error) {
180					const executionTime = performance.now() - startTime;
181	
182					logger.error(
183						`Failed after ${executionTime.toFixed(2)}ms: ${(error as Error).message}`,
184						(error as Error).stack,
185					);
186	
187					throw error;
188				}
189			};
190	
191			return descriptor;
192		};
193	}
