31	async function bootstrap(): Promise<NestFastifyApplication> {
32		const port = getEnv<number>({ key: PORT, converter: Number });
33		const globalPrefix = getEnv<string>({ key: GLOBAL_PREFIX });
34		const nodeEnv = getEnv<Environment>({ key: NODE_ENV });
35		const isDev = nodeEnv === Environment.DEVELOPMENT;
36		const serverName = getEnv<string>({ key: SERVER_NAME });
37		const isCompactLogs = getEnv<boolean>({ key: IS_COMPACT_LOGS, converter: Boolean });
38		const isJsonLikeLogs = getEnv<boolean>({ key: IS_JSON_LIKE_LOGS, converter: Boolean });
39	
40		const logger = new AppConsoleLogger({
41			logLevels: isDev
42				? ['log', 'error', 'warn', 'fatal', 'debug', 'verbose']
43				: ['log', 'error', 'warn', 'fatal'],
44			colors: isDev,
45			prefix: serverName,
46			compact: isCompactLogs,
47			json: isJsonLikeLogs,
48		});
49	
50		const fastifyAdapter = new FastifyAdapter({ trustProxy: true });
51	
52		await fastifyAdapter.getInstance().register(fastifyHttpLogger);
53	
54		const app = await NestFactory.create<NestFastifyApplication>(
55			AppModule,
56			fastifyAdapter,
57			{ logger },
58		);
59	
60		await app.register(fastifyCookie);
61	
62		app.enableCors({
63			origin: getEnv<string>({ key: FRONTEND_URL }),
64			credentials: true,
65			allowedHeaders: ['content-type', 'authorization', 'x-csrf-token'],
66		});
67	
68		app.useGlobalPipes(
69			new ValidationPipe({ transform: true, whitelist: true, forbidNonWhitelisted: true }),
70		);
71	
72		app.setGlobalPrefix(globalPrefix, {
73			exclude: ['liveness', 'readiness'],
74		});
75	
76		setupSwagger({ app, fastifyAdapter, globalPrefix });
77	
78		if (!isDev) {
79			app.enableShutdownHooks();
80		}
81	
82		await app.listen(port, '0.0.0.0');
83	
84		Logger.log(`Application running on port ${String(port)}`, 'Bootstrap');
85	
86		return app;
87	}
88	
89	let app: NestFastifyApplication | undefined;
90	
91	async function startApp(): Promise<void> {
92		try {
93			app = await bootstrap();
94		} catch (err: unknown) {
95			Logger.error('Failed to start application', err, 'Bootstrap');
96			process.exit(1);
97		}
98	}
