1	import { randomUUID } from 'node:crypto';
2	
3	import { Injectable, Logger } from '@nestjs/common';
4	import { Knex } from 'knex';
5	import { InjectConnection } from 'nest-knexjs';
6	
7	import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
8	import { IGithubApiRepo } from '@modules/github/types/github-api.interface';
9	import { IGithubRepoBase } from '@modules/github/types/github-repo.interface';
10	
11	import { TABLE_NAME_GITHUB_REPOS } from '@constants/db.constant';
12	
13	@Injectable()
14	export class GithubRepoModel {
15		private readonly logger = new Logger(GithubRepoModel.name);
16		private readonly tableName = TABLE_NAME_GITHUB_REPOS;
17	
18		constructor(
19			@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
20			@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
21		) {}
22	
23		async upsertMany({
24			installationId,
25			repos,
26		}: {
27			installationId: string;
28			repos: IGithubApiRepo[];
29		}): Promise<void> {
30			if (repos.length === 0) return;
31	
32			try {
33				const rows = repos.map((repo) => ({
34					_id: randomUUID(),
35					installation_id: installationId,
36					github_repo_id: repo.id,
37					name: repo.name,
38					full_name: repo.full_name,
39					private: repo.private,
40					default_branch: repo.default_branch,
41					created_at: this.knexWrite.fn.now(),
42					updated_at: this.knexWrite.fn.now(),
43				}));
44	
45				await this.knexWrite<IGithubRepoBase>(this.tableName)
46					.insert(rows)
47					.onConflict('github_repo_id')
48					.merge([
49						'installation_id',
50						'name',
51						'full_name',
52						'private',
53						'default_branch',
54						'updated_at',
55					]);
56	
57				this.logger.debug(`Upserted ${repos.length} repos for installation ${installationId}`);
58			} catch (error) {
59				this.logger.error(
60					`Failed to upsert repos for installation ${installationId}: ${(error as Error).message}`,
61				);
62				throw error;
63			}
64		}
65	
66		async findByInstallationId({
67			installationId,
68		}: {
69			installationId: string;
70		}): Promise<IGithubRepoBase[]> {
71			try {
72				return await this.knexRead<IGithubRepoBase>(this.tableName)
73					.where({ installation_id: installationId })
74					.select('*');
75			} catch (error) {
76				this.logger.error(
77					`Failed to find repos for installation ${installationId}: ${(error as Error).message}`,
78				);
79				throw error;
80			}
81		}
82	
83		async removeByGithubIds({
84			installationId,
85			githubRepoIds,
86		}: {
87			installationId: string;
88			githubRepoIds: number[];
89		}): Promise<void> {
90			if (githubRepoIds.length === 0) return;
91	
92			try {
93				await this.knexWrite<IGithubRepoBase>(this.tableName)
94					.where({ installation_id: installationId })
95					.whereIn('github_repo_id', githubRepoIds)
96					.delete();
97	
98				this.logger.debug(
99					`Removed ${githubRepoIds.length} repos from installation ${installationId}`,
100				);
101			} catch (error) {
102				this.logger.error(
103					`Failed to remove repos from installation ${installationId}: ${(error as Error).message}`,
104				);
105				throw error;
106			}
107		}
108	}
