import { randomUUID } from 'crypto';

import fastifyCookie from '@fastify/cookie';
import { HttpService } from '@nestjs/axios';
import { ValidationPipe } from '@nestjs/common';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import { Test, TestingModule } from '@nestjs/testing';
import { Redis } from 'ioredis';
import Knex from 'knex';
import * as request from 'supertest';

import { AppModule } from '@modules/app/app.module';
import { REDIS_WRITE_CLIENT } from '@modules/cache/cache.constant';
import { GithubAppService } from '@modules/github/github-app.service';
import { GithubInstallationModel } from '@modules/github/db/github-installations.model';
import { GithubInstallationStatus } from '@modules/github/types/github-installation.interface';

import type { App } from 'supertest/types';

import {
	cleanDatabase,
	cleanRedis,
	createAccessToken,
	createSession,
	createTestUser,
	insertCompany,
	insertCompanyMember,
	insertUser,
} from './helpers/auth.helper';

async function cleanGithubTables({ knex }: { knex: Knex.Knex }): Promise<void> {
	await knex.raw('TRUNCATE TABLE github_repos, github_installations CASCADE');
}

describe('GithubModule (e2e)', () => {
	let app: NestFastifyApplication;
	let httpServer: App;
	let knex: Knex.Knex;
	let redis: Redis;
	let moduleFixture: TestingModule;
	let httpService: HttpService;
	let githubAppService: GithubAppService;
	let githubInstallationModel: GithubInstallationModel;

	beforeAll(async () => {
		moduleFixture = await Test.createTestingModule({
			imports: [AppModule],
		}).compile();

		app = moduleFixture.createNestApplication<NestFastifyApplication>(new FastifyAdapter());
		await app.register(fastifyCookie);

		app.useGlobalPipes(
			new ValidationPipe({ transform: true, whitelist: true, forbidNonWhitelisted: true }),
		);

		app.setGlobalPrefix('api', { exclude: ['liveness', 'readiness'] });

		await app.init();
		await app.getHttpAdapter().getInstance().ready();

		httpServer = app.getHttpServer() as App;

		knex = Knex({
			client: 'pg',
			connection: process.env['DATABASE_URL']!,
		});

		redis = moduleFixture.get<Redis>(REDIS_WRITE_CLIENT);
		httpService = moduleFixture.get<HttpService>(HttpService);
		githubAppService = moduleFixture.get<GithubAppService>(GithubAppService);
		githubInstallationModel = moduleFixture.get<GithubInstallationModel>(
			GithubInstallationModel,
		);

		await knex.migrate.latest({ directory: './src/migrations' });
	});

	afterAll(async () => {
		await cleanDatabase({ knex });
		await cleanGithubTables({ knex });
		await cleanRedis({ redis });
		await knex.destroy();
		await app.close();
	});

	beforeEach(async () => {
		await cleanDatabase({ knex });
		await cleanGithubTables({ knex });
		await cleanRedis({ redis });
		jest.restoreAllMocks();
	});

	describe('POST /api/integrations/github/connect', () => {
		it('should return 200 with GitHub install URL for admin user', async () => {
			const user = createTestUser({ email: `gh-connect-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: 'Test Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'admin',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const res = await request(httpServer)
				.post('/api/integrations/github/connect')
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(res.status).toBe(200);
			expect(res.body).toHaveProperty('url');
			expect(res.body.url).toContain('https://github.com/apps/');
			expect(res.body.url).toContain('/installations/new?state=');
		});

		it('should return 401 when unauthenticated', async () => {
			const res = await request(httpServer)
				.post('/api/integrations/github/connect')
				.send();

			expect(res.status).toBe(401);
		});

		it('should return 403 when user has member role', async () => {
			const user = createTestUser({ email: `gh-member-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: 'Test Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'member',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'member',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'member',
				companyId: company._id,
			});

			const res = await request(httpServer)
				.post('/api/integrations/github/connect')
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(res.status).toBe(403);
		});
	});

	describe('GET /api/integrations/github/callback', () => {
		it('should redirect to frontend success page on valid callback', async () => {
			jest.spyOn(githubAppService, 'generateAppJwt').mockReturnValue('mock-jwt');
			jest
				.spyOn(httpService.axiosRef, 'get')
				.mockResolvedValue({
					data: {
						id: 12345678,
						account: { login: 'acme-corp', id: 987654 },
					},
					status: 200,
					statusText: 'OK',
					headers: {},
					config: {},
				});
			jest
				.spyOn(httpService.axiosRef, 'post')
				.mockResolvedValue({
					data: { token: 'mock-install-token', expires_at: new Date().toISOString() },
					status: 201,
					statusText: 'Created',
					headers: {},
					config: {},
				});

			const state = randomUUID();
			await redis.set(
				`github_install_state:${state}`,
				JSON.stringify({ companyId: 'company-uuid-1', userId: 'user-uuid-1' }),
				'EX',
				300,
			);

