import {
	CanActivate,
	ExecutionContext,
	ForbiddenException,
	Injectable,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';

import { ROLES_KEY } from '@modules/auth/decorators/roles.decorator';
import { IRequestUser } from '@modules/auth/types/auth.interface';

import type { FastifyRequest } from 'fastify';

@Injectable()
export class RolesGuard implements CanActivate {
	constructor(private readonly reflector: Reflector) {}

	canActivate(context: ExecutionContext): boolean {
		const requiredRoles = this.reflector.getAllAndOverride<('admin' | 'member')[]>(
			ROLES_KEY,
			[context.getHandler(), context.getClass()],
		);

		// eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
		if (!requiredRoles || requiredRoles.length === 0) return true;

		const request = context
			.switchToHttp()
			.getRequest<FastifyRequest & { user?: IRequestUser }>();
		const user = request.user;

		if (!user) throw new ForbiddenException();
		if (!user.role) throw new ForbiddenException();
		if (!requiredRoles.includes(user.role)) throw new ForbiddenException();

		return true;
	}
}

