1	import {
2		CanActivate,
3		ExecutionContext,
4		Injectable,
5		UnauthorizedException,
6	} from '@nestjs/common';
7	import { Reflector } from '@nestjs/core';
8	import { JwtService } from '@nestjs/jwt';
9	
10	import { IS_PUBLIC_KEY } from '@modules/auth/decorators/public.decorator';
11	import { IJwtPayload, IRequestUser } from '@modules/auth/types/auth.interface';
12	import { SessionService } from '@modules/session/session.service';
13	
14	import type { FastifyRequest } from 'fastify';
15	
16	@Injectable()
17	export class AuthGuard implements CanActivate {
18		constructor(
19			private readonly jwtService: JwtService,
20			private readonly sessionService: SessionService,
21			private readonly reflector: Reflector,
22		) {}
23	
24		async canActivate(context: ExecutionContext): Promise<boolean> {
25			const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
26				context.getHandler(),
27				context.getClass(),
28			]);
29	
30			const request = context
31				.switchToHttp()
32				.getRequest<FastifyRequest & { user?: IRequestUser }>();
33			const token = this.extractTokenFromHeader(request);
34	
35			if (isPublic) {
36				if (token) {
37					await this.tryPopulateUser({ request, token });
38				}
39				return true;
40			}
41	
42			if (!token) throw new UnauthorizedException();
43	
44			let payload: IJwtPayload;
45			try {
46				payload = await this.jwtService.verifyAsync<IJwtPayload>(token);
47			} catch {
48				throw new UnauthorizedException();
49			}
50	
51			const session = await this.sessionService.getSession({
52				userId: payload.user_id,
53				sessionId: payload.session_id,
54			});
55			if (!session) throw new UnauthorizedException();
56	
57			request.user = {
58				user_id: payload.user_id,
59				session_id: payload.session_id,
60				role: session.role,
61				company_id: session.company_id,
62			} satisfies IRequestUser;
63	
64			return true;
65		}
66	
67		private async tryPopulateUser({
68			request,
69			token,
70		}: {
71			request: FastifyRequest & { user?: IRequestUser };
72			token: string;
73		}): Promise<void> {
74			const payload = await this.jwtService
75				.verifyAsync<IJwtPayload>(token)
76				.catch(() => null);
77			if (!payload) return;
78	
79			const session = await this.sessionService.getSession({
80				userId: payload.user_id,
81				sessionId: payload.session_id,
82			});
83			if (!session) return;
84	
85			request.user = {
86				user_id: payload.user_id,
87				session_id: payload.session_id,
88				role: session.role,
89				company_id: session.company_id,
90			} satisfies IRequestUser;
91		}
92	
93		private extractTokenFromHeader({ headers }: FastifyRequest): string | null {
94			const [type, token] = headers.authorization?.split(' ') ?? [];
95			return type === 'Bearer' ? (token ?? null) : null;
96		}
97	}
